    trim_task.cancel()
    # ── Graceful shutdown: stop accepting, drain active connections ─
    if server is not None:
        server.close()
        await server.wait_closed()
    elif unix_sock is not None:
        try:
            if sys.platform != "win32":
                loop.remove_reader(unix_sock.fileno())
            unix_sock.close()
        except OSError:
            pass

